mapper.select:
select * from orders


        and number like concat('%', #{number}, '%')


        and phone like concat('%', #{phone}, '%')


        and status = #{status}


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


        and user_id = #{userId}


order by order_time desc

select sum(amount) from orders


        and order_time > #{begin}


        and order_time < #{end}


        and status = #{status}

select count(*) from orders


        and order_time
        >
        #{begin}


        and order_time
        <
        #{end}


        and status = #{status}

select od.name, sum(od.number) as saleCount from order_detail od, orders o where od.order_id = o.id and o.status = 5
and o.order_time > #{begin}
and o.order_time < #{end}
group by od.name order by saleCount desc limit 10
